import{_ as e,c as l,o as i,a4 as t}from"./chunks/framework.BxjRYGQi.js";const c=JSON.parse('{"title":"上海捷勃特机器人（Agilebot）-ROS2软件包","description":"","frontmatter":{},"headers":[],"relativePath":"zh/index.md","filePath":"zh/index.md"}'),r={name:"zh/index.md"};function o(n,a,s,h,g,d){return i(),l("div",{"data-pagefind-body":!0},a[0]||(a[0]=[t('<h1 id="上海捷勃特机器人agilebot-ros2软件包" tabindex="-1">上海捷勃特机器人（Agilebot）-ROS2 软件包 <a class="header-anchor" href="#上海捷勃特机器人agilebot-ros2软件包" aria-label="Permalink to “上海捷勃特机器人（Agilebot）-ROS2软件包”">​</a></h1><h2 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to “项目概述”">​</a></h2><p>本项目提供上海捷勃特机器人的 ROS2 工具包，旨在帮助用户快速集成和开发机器人应用。工具包包含以下内容：</p><ol><li><p><strong>协作机器人 URDF 模型</strong><br> 提供标准化 URDF 描述文件，支持机器人三维建模与仿真。</p></li><li><p><strong>ROS2 驱动包</strong><br> 实现机器人控制与通信功能，支持：</p><ul><li>控制程序执行</li><li>发送程序脚本给机器人执行</li><li>获取机器人状态信息（关节 / 末端数据、报警信息等）</li><li>显示机器人当前姿态</li></ul></li><li><p><strong>示例代码与教程</strong><br> 包含典型应用案例，指导用户完成，包括但不限于：</p><ul><li>使用 MoveIt 进行运动规划，并转译给捷勃特机器人执行</li><li>离线轨迹文件的导入与执行</li><li>集成捷勃特的视觉软件 AgileGaze</li><li>发送自定义程序脚本</li><li>视觉码垛 demo</li></ul></li></ol><p>该工具包通过提供完整开发资源，降低机器人集成难度，提升开发效率。</p><h2 id="文档目录" tabindex="-1">文档目录 <a class="header-anchor" href="#文档目录" aria-label="Permalink to “文档目录”">​</a></h2><ul><li><a href="./01-installation/">安装指南</a></li><li><a href="./02-quick-start/">快速开始</a></li><li><a href="./03-example/">示例</a></li><li><a href="./04-faq/">常见问题</a></li><li><a href="./05-roadmap/">开发计划</a></li><li><a href="./06-license/">许可证</a></li></ul><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to “联系方式”">​</a></h2><p>如果您有任何建议或希望参与项目的开发，请通过以下方式联系我们：</p><ul><li><strong>公司官网</strong>：<a href="https://www.sh-agilebot.com/" target="_blank" rel="noreferrer">https://www.sh-agilebot.com/</a></li><li><strong>邮箱</strong>: <a href="mailto:info@agilebot.com.cn" target="_blank" rel="noreferrer">info@agilebot.com.cn</a></li><li><strong>电话</strong>: <code>400-996-7588</code></li><li><strong>GitHub</strong>: <a href="https://github.com/sh-agilebot/Agilebot_Robot_Ros2" target="_blank" rel="noreferrer">https://github.com/sh-agilebot/Agilebot_Robot_Ros2</a></li></ul>',10)]))}const p=e(r,[["render",o]]);export{c as __pageData,p as default};
